-- 音楽会場データ投入 (1.0.5: Tonight in Tokyo)
-- 元データ: /Volumes/Toshi SSD/開発/収益拡大戦略/import/music_venues_valid.json
-- 件数: 143

BEGIN;

-- walk_in CHECK 制約を実データの値域 (high/medium/low) に合わせる
ALTER TABLE public.music_venues
  DROP CONSTRAINT IF EXISTS music_venues_walk_in_check;
ALTER TABLE public.music_venues
  ADD CONSTRAINT music_venues_walk_in_check
  CHECK (walk_in IN ('high', 'medium', 'low'));

COMMENT ON COLUMN public.music_venues.walk_in IS 'high=ふらっと入店容易 / medium=要予約推奨 / low=要事前予約・チケット';

-- 既存データ（あれば）を全削除して再投入（冪等性確保）
TRUNCATE TABLE public.music_venues RESTART IDENTITY;

INSERT INTO public.music_venues (
  category, name, name_en, address, ward,
  latitude, longitude, official_url, phone,
  cover_min, cover_max, walk_in,
  description_ja, description_en, genre_tags, note
) VALUES
  ('classical', 'サントリーホール', 'Suntory Hall', '港区赤坂1-13-1', '港区', 35.671, 139.74, 'https://www.suntory.co.jp/suntoryhall/', '+81-3-3505-1001', 3000, 15000, 'low', '日本を代表するヴィンヤード型コンサートホール。世界最高峰のオーケストラが定期的に来演し、音響の良さで知られる。週末公演はチケット争奪戦になることが多い。', 'Japan''s premier vineyard-style concert hall, hosting world-class orchestras and renowned for exceptional acoustics. Weekend performances often sell out quickly.', 'classical,orchestra,chamber,organ', '6,000席級の大ホールとブルーローズ（小ホール）の二館構成'),
  ('classical', '東京文化会館', 'Tokyo Bunka Kaikan', '台東区上野公園5-45', '台東区', 35.715, 139.776, 'https://www.t-bunka.jp/', '+81-3-3828-2111', 2000, 12000, 'medium', '上野公園内の文化施設。前川國男設計のモダニズム建築で、オペラ・バレエ・オーケストラ公演が中心。当日券あり。', 'A modernist landmark designed by Kunio Maekawa in Ueno Park, hosting opera, ballet and orchestral performances. Same-day tickets often available.', 'classical,opera,ballet,orchestra', '上野駅から徒歩1分。観光ついでに立ち寄りやすい'),
  ('classical', 'Bunkamura オーチャードホール', 'Bunkamura Orchard Hall', '渋谷区道玄坂2-24-1', '渋谷区', 35.659, 139.697, 'https://www.bunkamura.co.jp/', '+81-3-3477-9111', 4000, 18000, 'low', '渋谷の文化複合施設内の大ホール。東京フィルハーモニー交響楽団のフランチャイズ。', 'A large hall in Shibuya''s Bunkamura complex, home to the Tokyo Philharmonic Orchestra.', 'classical,orchestra,ballet', '2027年1月から大規模改修で全館休館予定。2026年中は週末・祝日中心に営業中（2026年確認済み）'),
  ('classical', '東京オペラシティ コンサートホール', 'Tokyo Opera City Concert Hall', '新宿区西新宿3-20-2', '新宿区', 35.683, 139.687, 'https://www.operacity.jp/concert/', '+81-3-5353-9999', 2500, 12000, 'medium', '「タケミツメモリアル」の愛称。ピラミッド型の天井と木質内装で残響豊かな音響。', 'Nicknamed ''Takemitsu Memorial,'' featuring a pyramid-shaped wooden interior with rich acoustics.', 'classical,orchestra,recital', '初台駅直結。リサイタル開催も多い'),
  ('classical', '紀尾井ホール', 'Kioi Hall', '千代田区紀尾井町6-5', '千代田区', 35.681, 139.737, 'https://kioihall.jp/', '+81-3-5276-4500', 3000, 8000, 'medium', '新日本フィルの旧フランチャイズ。室内楽と古楽に強い800席の中ホール。', 'An 800-seat hall specializing in chamber music and early music repertoire.', 'classical,chamber,early music', '紀尾井シンフォニエッタ東京が拠点'),
  ('classical', 'トッパンホール', 'Toppan Hall', '文京区水道1-3-3', '文京区', 35.706, 139.748, 'https://www.toppanhall.com/', '+81-3-5840-2222', 4000, 9000, 'medium', '凸版印刷が運営する408席のシューボックス型ホール。室内楽・歌曲のリサイタルで定評。', 'A 408-seat shoebox hall operated by Toppan Printing, highly regarded for chamber and lieder recitals.', 'classical,chamber,recital', '音響重視の本格派ホール'),
  ('classical', '第一生命ホール', 'Dai-ichi Seimei Hall', '中央区晴海1-8-1', '中央区', 35.658, 139.776, 'https://www.dai-ichi-seimei-hall.jp/', '+81-3-3532-3535', 3000, 7000, 'medium', '晴海トリトンスクエア内。室内楽中心のプログラム。', 'Located in Harumi Triton Square, with programming centered on chamber music.', 'classical,chamber', '勝どき駅から徒歩'),
  ('classical', '浜離宮朝日ホール', 'Hamarikyu Asahi Hall', '中央区築地5-3-2', '中央区', 35.667, 139.77, 'https://www.asahi.com/asahihall/', '+81-3-5541-8710', 3500, 9000, 'medium', '朝日新聞東京本社内の552席ホール。木質内装で室内楽・ジャズも開催。', 'A 552-seat hall in the Asahi Shimbun building, hosting chamber music and jazz events.', 'classical,chamber,jazz', '築地から徒歩'),
  ('classical', '東京芸術劇場 コンサートホール', 'Tokyo Metropolitan Theatre Concert Hall', '豊島区西池袋1-8-1', '豊島区', 35.73, 139.711, 'https://www.geigeki.jp/', '+81-3-5391-2111', 2000, 10000, 'medium', '池袋駅西口直結。世界最大級のパイプオルガンを擁する2000席のホール。', 'Linked directly to Ikebukuro Station, featuring one of the world''s largest pipe organs and a 2,000-seat hall.', 'classical,organ,orchestra', 'オルガンランチタイムコンサート（無料）も実施'),
  ('classical', 'NHKホール', 'NHK Hall', '渋谷区神南2-2-1', '渋谷区', 35.665, 139.694, 'https://www.nhk-sc.or.jp/nhk_hall/', '+81-3-3465-1751', 3000, 12000, 'low', 'NHK交響楽団の本拠地。3,400席の大ホール。', 'Home of the NHK Symphony Orchestra, a large 3,400-seat venue.', 'classical,orchestra', '定期演奏会の当日券は限定的'),
  ('classical', 'サントリーホール ブルーローズ', 'Suntory Hall Blue Rose', '港区赤坂1-13-1', '港区', 35.671, 139.74, 'https://www.suntory.co.jp/suntoryhall/', '+81-3-3505-1001', 3000, 7000, 'medium', 'サントリーホール内の小ホール。384席。室内楽・ジャズ・現代音楽に対応。', 'The smaller hall at Suntory Hall, 384 seats, used for chamber music, jazz, and contemporary works.', 'classical,chamber,jazz', '本館とは別エントランス'),
  ('classical', '王子ホール', 'Oji Hall', '中央区銀座4-7-5', '中央区', 35.671, 139.766, 'https://www.ojihall.jp/', '+81-3-3567-9990', 4500, 9000, 'medium', '銀座中心地にある315席の室内楽ホール。木質内装で響きが美しい。', 'A 315-seat chamber music hall in central Ginza, with warm wood interiors and beautiful acoustics.', 'classical,chamber,recital', '王子製紙運営'),
  ('classical', '津田ホール', 'Tsuda Hall', '渋谷区千駄ヶ谷1-18-24', '渋谷区', 35.681, 139.711, 'https://tsudahall.com/', '+81-3-3402-1851', 3000, 7000, 'medium', '津田塾大学の490席ホール。室内楽・声楽リサイタルが中心。', 'A 490-seat hall owned by Tsuda University, focused on chamber and vocal recitals.', 'classical,chamber,recital', '千駄ケ谷駅近く'),
