  ('classical', '旧東京音楽学校奏楽堂', 'Former Tokyo Music School Sogakudo', '台東区上野公園8-43', '台東区', 35.717, 139.774, 'https://www.taitogeibun.net/sogakudo/', '+81-3-3824-1988', 500, 3000, 'high', '上野公園内の重要文化財。日本最古の本格的洋式音楽ホール。', 'An important cultural property in Ueno Park—the oldest Western-style concert hall in Japan.', 'classical,recital,organ', '日曜オルガンコンサートあり'),
  ('classical', 'Hakuju Hall', 'Hakuju Hall', '渋谷区富ヶ谷1-37-5', '渋谷区', 35.671, 139.685, 'https://www.hakujuhall.jp/', '+81-3-5478-8867', 4000, 8000, 'medium', '代々木八幡の300席ホール。リサイタル中心。', 'A 300-seat hall in Yoyogi-Hachiman, focused on recitals.', 'classical,chamber', '小規模だが音響評価高い'),
  ('classical', '春秋座（区民会館系）', 'Tokyo Civic Hall (placeholder)', '新宿区四谷区民ホール 四谷4-17', '新宿区', 35.687, 139.72, 'https://www.regasu-shinjuku.or.jp/', '+81-3-3351-3314', 1000, 4000, 'medium', '四谷区民ホール（新宿区）。アマチュア演奏会中心。', 'A community hall in Yotsuya (Shinjuku Ward), mainly amateur concerts.', 'classical,recital', '低価格'),
  ('classical', '紀尾井小ホール', 'Kioi Small Hall', '千代田区紀尾井町6-5', '千代田区', 35.681, 139.737, 'https://kioihall.jp/', '+81-3-5276-4500', 3000, 6000, 'medium', '紀尾井ホール内の250席小ホール。邦楽・古楽の上演も多い。', 'A 250-seat hall within Kioi Hall, often used for traditional Japanese music and early music.', 'classical,chamber,early music,hougaku', '邦楽カテゴリーとも重複'),
  ('classical', '東京文化会館 小ホール', 'Tokyo Bunka Kaikan Small Hall', '台東区上野公園5-45', '台東区', 35.715, 139.776, 'https://www.t-bunka.jp/', '+81-3-3828-2111', 2000, 6000, 'medium', '東京文化会館内の649席小ホール。リサイタル・室内楽。', 'A 649-seat hall within Tokyo Bunka Kaikan for recitals and chamber music.', 'classical,recital,chamber', '上野駅前'),
