  ('jazz_live', 'STB139 スイートベイジル', 'STB139 Sweet Basil', '港区六本木6-7-11', '港区', 35.663, 139.732, 'https://www.stb139.co.jp/', '+81-3-5474-0139', 5000, 10000, 'medium', '六本木の大型ライブレストラン。ジャズ・フュージョン中心。', 'A large live-music restaurant in Roppongi featuring jazz and fusion.', 'jazz,fusion,vocal', '食事込みプラン'),
  ('jazz_live', 'Blue Note Tokyo', 'Blue Note Tokyo', '港区南青山6-3-16 ライカビル', '港区', 35.661, 139.715, 'https://www.bluenote.co.jp/', '+81-3-5485-0088', 6000, 15000, 'medium', '世界的ブランドの東京旗艦店。海外大物アーティストが連夜出演。事前予約必須に近い。', 'The Tokyo flagship of the global Blue Note brand, hosting major international artists nightly. Reservations strongly recommended.', 'jazz,fusion,vocal', '2公演制・着席フォーマル'),
  ('jazz_live', 'Cotton Club Tokyo', 'Cotton Club Tokyo', '千代田区丸の内2-7-3 東京ビルTOKIA 2F', '千代田区', 35.679, 139.764, 'https://www.cottonclubjapan.co.jp/', '+81-3-3215-1555', 6000, 15000, 'medium', 'Blue Note姉妹店。丸の内の高級ディナージャズクラブ。', 'A sister venue to Blue Note Tokyo, an upscale dinner-jazz club in Marunouchi.', 'jazz,vocal,soul', 'ドレスコード緩め'),
  ('jazz_live', 'Birdland (Tokyo)', 'Birdland Roppongi', '港区六本木3-12-7', '港区', 35.663, 139.736, 'https://www.bird-land.co.jp/', NULL, 3500, 6000, 'medium', '六本木の老舗ジャズクラブ。落ち着いた大人の空間。', 'An established Roppongi jazz club with a refined adult atmosphere.', 'jazz,mainstream', '1974年開店のハワイアン&ジャズライブハウス。2026年営業確認済み。住所はビル要再確認'),
  ('jazz_live', 'Jirokichi', 'Jirokichi', '中野区高円寺北2-3-4 アサミビルB1', '中野区', 35.706, 139.65, 'https://jirokichi.net/', '+81-3-3339-2727', 2500, 4000, 'high', '高円寺の老舗ライブハウス。ジャズ・ブルース・即興系の聖地的存在。', 'A long-running live house in Koenji, central to Tokyo''s jazz, blues, and improvised music scenes.', 'jazz,blues,rock,improvised', 'カウンター席メイン'),
